function sf_qa_environment_checks(): array { $checks=[]; $checks[]=sf_qa_status(version_compare(PHP_VERSION,'8.1.0','>=')?'pass':'fail','PHP version 8.1+',PHP_VERSION,2); $checks[]=sf_qa_status(extension_loaded('pdo')?'pass':'fail','PDO extension',extension_loaded('pdo')?'Loaded':'Missing',2); $checks[]=sf_qa_status(extension_loaded('pdo_mysql')?'pass':'warn','PDO MySQL extension',extension_loaded('pdo_mysql')?'Loaded':'Required on production',2); $checks[]=sf_qa_status(extension_loaded('json')?'pass':'fail','JSON extension',extension_loaded('json')?'Loaded':'Missing'); $checks[]=sf_qa_status(extension_loaded('fileinfo')?'pass':'warn','Fileinfo extension',extension_loaded('fileinfo')?'Loaded':'Recommended for uploads'); $checks[]=sf_qa_status(function_exists('password_hash')?'pass':'fail','Password hashing','Auth layer can hash passwords',2); $checks[]=sf_qa_status(sf_qa_db_ready()?'pass':'preview','Database connection',sf_qa_db_ready()?'Connected':'Static/no-database preview mode'); foreach(['config','storage','assets/images/uploads','assets/audio/uploads','assets/video/uploads','assets/documents/uploads'] as $dir){ $path=sf_qa_file_path($dir); $checks[]=sf_qa_status(is_dir($path)&&is_writable($path)?'pass':(is_dir($path)?'warn':'fail'),'Writable folder: '.$dir,is_dir($path)?(is_writable($path)?'Writable':'Exists but not writable'):'Missing',2); } foreach(['.env.example','deploy/preflight.php','docs/DEPLOYMENT_RUNBOOK.md'] as $file) $checks[]=sf_qa_status(sf_qa_file_exists($file)?'pass':'fail','Deployment file: '.$file,sf_qa_file_exists($file)?'Present':'Missing'); return $checks; }
function sf_qa_migration_checks(): array { $checks=[]; foreach(sf_qa_migration_plan() as $migration){ $fileOk=sf_qa_file_exists($migration['file']); $missing=[]; if(sf_qa_db_ready()) foreach($migration['tables'] as $table) if(!sf_qa_table_exists($table)) $missing[]=$table; $status=sf_qa_db_ready()?($fileOk&&!$missing?'pass':'fail'):($fileOk?'preview':'fail'); $detail=$fileOk?(!$missing?'File present'.(sf_qa_db_ready()?' and tables installed':'; database not connected for table verification'):'Missing tables: '.implode(', ',$missing)):'SQL file missing'; $checks[]=sf_qa_status($status,$migration['key'].' — '.$migration['label'],$detail,2); } foreach(sf_qa_required_columns() as $table=>$columns){ if(!sf_qa_db_ready()){ $checks[]=sf_qa_status('preview','Columns: '.$table,'Database not connected; expected columns are documented'); continue; } if(!sf_qa_table_exists($table)){ $checks[]=sf_qa_status('fail','Columns: '.$table,'Table missing',2); continue; } $missing=array_values(array_diff($columns,sf_qa_columns($table))); $checks[]=sf_qa_status($missing?'fail':'pass','Columns: '.$table,$missing?'Missing columns: '.implode(', ',$missing):'Required columns present',2); } return $checks; }

