function sf_qa_route_checks(): array { $checks=[]; foreach(sf_qa_public_routes() as $route){ $exists=sf_qa_file_exists($route['path']); $usesHeader=sf_qa_contains($route['path'],['includes/header.php',"require __DIR__ . '/includes/header.php'","require_once __DIR__ . '/includes/header.php'"]); $checks[]=sf_qa_status($exists&&$usesHeader?'pass':($exists?'warn':'fail'),$route['label'].' — '.$route['path'],$exists?($usesHeader?'Full page route present':'Route exists; header include not detected'):'Route file missing',2); } foreach(sf_qa_admin_routes() as $route){ $exists=sf_qa_file_exists($route['path']); $protected=sf_qa_contains($route['path'],['includes/admin_catalog.php','/../includes/admin_catalog.php','includes/admin_analytics.php','/../includes/admin_analytics.php','includes/qa.php','/../includes/qa.php']) || sf_qa_contains('includes/admin_catalog.php',['sf_require_admin']); $checks[]=sf_qa_status($exists&&$protected?'pass':($exists?'warn':'fail'),$route['label'].' — '.$route['path'],$exists?($protected?'Admin shell/protection detected':'Admin protection not detected'):'Route file missing',2); } foreach(sf_qa_api_routes() as $route){ $exists=sf_qa_file_exists($route['path']); $json=sf_qa_contains($route['path'],['sf_json_response']); $checks[]=sf_qa_status($exists&&$json?'pass':($exists?'warn':'fail'),$route['label'].' — '.$route['path'],$exists?($json?'JSON response contract detected':'JSON response helper not detected'):'API file missing',2); } foreach(sf_qa_utility_routes() as $route){ $checks[]=sf_qa_status(sf_qa_file_exists($route['path'])?'pass':'fail',$route['label'].' — '.$route['path'],sf_qa_file_exists($route['path'])?'Utility route present':'Utility route missing',2); } return $checks; }

function sf_qa_security_checks(): array { $checks=[]; $adminUnprotected=[]; foreach(sf_qa_admin_routes() as $route){ if(!sf_qa_file_exists($route['path'])) continue; $body=sf_qa_read_file($route['path']); if(strpos($body,'includes/admin_catalog.php')===false && strpos($body,'includes/admin_analytics.php')===false && strpos($body,'includes/qa.php')===false && strpos($body,'sf_require_admin')===false) $adminUnprotected[]=$route['path']; } $checks[]=sf_qa_status(!$adminUnprotected?'pass':'fail','Admin route protection',!$adminUnprotected?'All admin pages use the admin shell/protection layer':'Missing protection: '.implode(', ',$adminUnprotected),3); $checks[]=sf_qa_status(sf_qa_contains('includes/auth.php',['password_hash','password_verify'])?'pass':'fail','Password security','Auth layer uses PHP password hashing/verification',3); $checks[]=sf_qa_status(sf_qa_contains('includes/auth.php',['random_bytes'])?'pass':'fail','Token generation','CSRF/reset/remember tokens use cryptographic randomness',2); $checks[]=sf_qa_status(sf_qa_contains('includes/admin_catalog.php',['mime_prefixes','max_bytes','move_uploaded_file'])?'pass':'fail','Upload validation','Upload manager validates extension, MIME family, max size, and controlled folders',3); $checks[]=sf_qa_status(sf_qa_contains('includes/media_delivery.php',['hash_hmac','hash_equals','Accept-Ranges'])?'pass':'fail','Signed media delivery','Media endpoint validates signatures and supports range streaming',3); $checks[]=sf_qa_status(sf_qa_contains('includes/payment_gateway.php',['sf_payment_verify_webhook','SF_STRIPE_WEBHOOK_SECRET'])?'pass':'fail','Gateway webhook verification','Gateway adapters isolate webhook verification',2); $checks[]=sf_qa_status(sf_qa_contains('includes/db.php',['PDO::ATTR_ERRMODE','PDO::ATTR_EMULATE_PREPARES'])?'pass':'fail','Database connection hardening','PDO exceptions and native prepares configured',2); return $checks; }
function sf_qa_normalize_asset_path(?string $path): string { $path=trim((string)$path); if($path===''||preg_match('~^(https?:)?//|^data:~i',$path))return ''; $path=ltrim($path,'/'); if(strpos($path,'assets/')===0)return $path; if(preg_match('~^(images|audio|video|documents)/~',$path))return 'assets/'.$path; return $path; }
function sf_qa_asset_exists(?string $path): bool { $normalized=sf_qa_normalize_asset_path($path); if($normalized==='')return true; return sf_qa_file_exists($normalized); }
function sf_qa_content_audit(): array { $items=[]; foreach(sf_admin_albums() as $album){$path=$album['cover_path']??$album['cover']??'';$items[]=['section'=>'Album','title'=>$album['title']??'Untitled album','field'=>'cover','path'=>$path,'status'=>$path===''?'warn':(sf_qa_asset_exists($path)?'pass':'fail')];} foreach(sf_admin_songs() as $song){foreach(['cover','cover_path','preview_src','full_src','preview_file_path','full_file_path'] as $field){ if(array_key_exists($field,$song)&&trim((string)$song[$field])!=='')$items[]=['section'=>'Song','title'=>$song['title']??'Untitled song','field'=>$field,'path'=>$song[$field],'status'=>sf_qa_asset_exists($song[$field])?'pass':'fail']; }} foreach(sf_admin_episodes() as $episode){foreach(['poster_path','thumbnail_path','hero_path','poster','image'] as $field){ if(array_key_exists($field,$episode)&&trim((string)$episode[$field])!=='')$items[]=['section'=>'Episode','title'=>$episode['title']??'Untitled episode','field'=>$field,'path'=>$episode[$field],'status'=>sf_qa_asset_exists($episode[$field])?'pass':'fail']; }} foreach(sf_admin_videos() as $video){foreach(['poster_path','poster','src','trailer_src','preview_src','stream_src','file_path'] as $field){ if(array_key_exists($field,$video)&&trim((string)$video[$field])!=='')$items[]=['section'=>'Video','title'=>$video['title']??'Untitled video','field'=>$field,'path'=>$video[$field],'status'=>sf_qa_asset_exists($video[$field])?'pass':'fail']; }} if(function_exists('sf_store_products')) foreach(sf_store_products() as $product){$path=$product['image']??$product['image_path']??'';$items[]=['section'=>'Product','title'=>$product['name']??'Product','field'=>'image','path'=>$path,'status'=>$path===''?'warn':(sf_qa_asset_exists($path)?'pass':'fail')];} return $items; }
function sf_qa_content_checks(): array { $checks=[]; $items=sf_qa_content_audit(); $fails=count(array_filter($items,fn($i)=>($i['status']??'')==='fail')); $warns=count(array_filter($items,fn($i)=>($i['status']??'')==='warn')); $checks[]=sf_qa_status($fails?'fail':($warns?'warn':'pass'),'Media asset references',$fails?($fails.' missing asset references'):($warns?$warns.' references need review':'All referenced assets exist'),3); $checks[]=sf_qa_status(count(sf_admin_albums())>0?'pass':'warn','Albums available',count(sf_admin_albums()).' album records'); $checks[]=sf_qa_status(count(sf_admin_songs())>0?'pass':'warn','Songs available',count(sf_admin_songs()).' song records'); $checks[]=sf_qa_status(count(sf_admin_videos())>0?'pass':'warn','Videos available',count(sf_admin_videos()).' video records'); return $checks; }
function sf_qa_launch_checklist(): array { return [['title'=>'Run installer','detail'=>'Visit install.php, confirm server checks, enter DB credentials, run SQL, create admin, and lock installer.','url'=>'install.php','cta'=>'Open Installer'],['title'=>'Open launch checklist','detail'=>'Use this page after installation to check score, route registry, migration status, and manual launch items.','url'=>'admin/launch-checklist.php','cta'=>'Checklist'],['title'=>'Verify route matrix','detail'=>'Confirm every public, admin, API, media, and deployment route is present.','url'=>'admin/routes-checker.php','cta'=>'Routes'],['title'=>'Verify migrations','detail'=>'Confirm base schema and migrations 001 through 013 are installed.','url'=>'admin/migration-checker.php','cta'=>'Migrations'],['title'=>'Verify secure media','detail'=>'Confirm member-only full files use signed stream/download delivery and protected storage.','url'=>'admin/media-delivery.php','cta'=>'Secure Media'],['title'=>'Configure payments','detail'=>'Keep sandbox active until Stripe/PayPal keys and webhooks are verified.','url'=>'admin/payment-gateways.php','cta'=>'Payments'],['title'=>'Run preflight','detail'=>'Open deploy/preflight.php or run it from CLI before public launch.','url'=>'deploy/preflight.php','cta'=>'Preflight']]; }
function sf_qa_all_checks(): array { return ['Environment'=>sf_qa_environment_checks(),'Migrations'=>sf_qa_migration_checks(),'Routes'=>sf_qa_route_checks(),'Security'=>sf_qa_security_checks(),'Content'=>sf_qa_content_checks()]; }
function sf_qa_flatten(array $sections): array { $flat=[]; foreach($sections as $section=>$checks) foreach($checks as $check){$check['section']=$section;$flat[]=$check;} return $flat; }
function sf_qa_persist_run(string $runType='manual'): ?int { if(!sf_qa_db_ready()||!sf_qa_table_exists('qa_runs')||!sf_qa_table_exists('qa_check_results'))return null; $sections=sf_qa_all_checks(); $flat=sf_qa_flatten($sections); $score=sf_qa_score($flat); $status=$score>=95?'passed':'review'; try{$pdo=sf_db();$pdo->beginTransaction();$stmt=$pdo->prepare('INSERT INTO qa_runs (run_type, score, status, summary_json, created_by_user_id) VALUES (?, ?, ?, ?, ?)');$stmt->execute([$runType,$score,$status,json_encode(['sections'=>array_keys($sections)],JSON_UNESCAPED_SLASHES),sf_current_user_id()]);$runId=(int)$pdo->lastInsertId();$insert=$pdo->prepare('INSERT INTO qa_check_results (qa_run_id, section, check_key, status, message, detail_json) VALUES (?, ?, ?, ?, ?, ?)');foreach($sections as $section=>$checks)foreach($checks as $index=>$check)$insert->execute([$runId,$section,strtolower(preg_replace('/[^a-z0-9]+/i','_',(string)($check['label']??'check_'.$index))),$check['status']??'info',$check['label']??'',json_encode($check,JSON_UNESCAPED_SLASHES)]);$pdo->commit();sf_admin_audit('qa_run','qa_runs',$runId,null,['score'=>$score,'status'=>$status]);return $runId;}catch(Throwable $e){if(isset($pdo)&&$pdo instanceof PDO&&$pdo->inTransaction())$pdo->rollBack();error_log('Stonefellow QA persist failed: '.$e->getMessage());return null;} }
function sf_qa_recent_runs(): array { if(!sf_qa_db_ready()||!sf_qa_table_exists('qa_runs'))return []; return sf_admin_fetch_all('SELECT * FROM qa_runs ORDER BY created_at DESC, id DESC LIMIT 20'); }
function sf_qa_section_summary(): array { $summary=[]; foreach(sf_qa_all_checks() as $section=>$checks)$summary[]=['section'=>$section,'score'=>sf_qa_score($checks),'count'=>count($checks),'fails'=>count(array_filter($checks,fn($check)=>in_array(($check['status']??''),['fail','missing'],true))),'warnings'=>count(array_filter($checks,fn($check)=>in_array(($check['status']??''),['warn','preview','manual'],true)))]; return $summary; }
function sf_qa_render_check_table(array $checks, bool $showSection=false): void { echo '<div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr>'; if($showSection)echo '<th>Section</th>'; echo '<th>Check</th><th>Status</th><th>Detail</th></tr></thead><tbody>'; foreach($checks as $check){ echo '<tr>'; if($showSection)echo '<td>'.sf_qa_h($check['section']??'').'</td>'; echo '<td><strong>'.sf_qa_h($check['label']??'').'</strong></td><td>'.sf_qa_badge((string)($check['status']??'info')).'</td><td>'.sf_qa_h($check['detail']??'').'</td></tr>'; } echo '</tbody></table></div>'; }
?>
